type WeatherConnection =
/** Our primary weather data provider */
"weatherprod"
/** Development environment, ONLY use for testing */
 | "weatherlocal";
type GetWeatherArgs = {
    /** City and state/country */
    location: string;
    /** Type of forecast */
    type: "current" | "hourly" | "daily";
    /** Number of days for daily forecast */
    days?: number;
};
type GetWeatherResult = {
    days: { date: string; high: number; low: number; condition: string; wind_mph: number; humidity: number }[];
};
/** Fetches weather data for a given location */
declare function getWeather(capability: WeatherConnection, args: GetWeatherArgs): Promise<GetWeatherResult>;

